}));
// â”€â”€ Stripe Webhook (must be before express.json() for raw body) â”€â”€
app.post('/api/stripe/webhook', express.raw({ type: 'application/json' }), async (req, res) => {
  try {
    const sig = req.headers['stripe-signature'] as string | undefined;
    const endpointSecret = process.env.STRIPE_WEBHOOK_SECRET;
    let event: any;

    if (endpointSecret && sig) {
      const stripe = require('stripe')(process.env.STRIPE_SECRET_KEY);
      try {
        event = stripe.webhooks.constructEvent(req.body, sig, endpointSecret);
      } catch (err: any) {
        console.error('[STRIPE WEBHOOK] Signature verification failed:', err.message);
        return res.status(400).send('Webhook signature verification failed');
      }
    } else {
      // Fallback: parse without verification (log warning)
      console.warn('[STRIPE WEBHOOK] WARNING: No STRIPE_WEBHOOK_SECRET configured, skipping signature verification');
      event = JSON.parse(req.body.toString());
    }
    if (event.type === 'checkout.session.completed') {
      const session = event.data.object;
      const customerEmail = session.customer_details?.email || session.customer_email;
      const amountTotal = session.amount_total; // in cents

      // Determine plan based on amount
      let plan = 'pro';
      if (amountTotal && amountTotal >= 7000) plan = 'business'; // 79â‚¬ = 7900 cents

