        VALUES (${recipeId}, ${ing.ingredient_name}, ${ing.quantity || 0}, ${ing.unit || 'kg'}, ${ing.price_per_unit || 0}, ${ing.total_cost || 0}, ${ing.supplier || 'Transgourmet'}, ${ing.image_url || null})
