        restaurantId: req.restaurantId,
        ingredients: {
          create: ingredientIds.map(i => ({ ingredientId: i.ingredientId, quantity: i.quantity, wastePercent: 0 })),
        },
      },
      include: { ingredients: { include: { ingredient: true } } },
    });
    res.status(201).json(recipe);
