${ingredientsList || 'Aucun ingrÃ©dient enregistrÃ©'}

=== MES FICHES TECHNIQUES (${recipes.length}) ===
${recipesList || 'Aucune recette'}

=== VARIATIONS DE PRIX RÃ‰CENTES ===
${recentAlerts.length > 0 ? recentAlerts.join('\n') : 'Aucune variation dÃ©tectÃ©e'}`;
}

