    return result.slice(0, 20);
  }, [filteredByPeriod, search]);

  // â”€â”€â”€ Handlers â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€

  async function handleAddWaste() {
    const ing = ingredients.find(i => i.id === parseInt(form.ingredientId));
    if (!ing) { showToast('SÃ©lectionnez un ingrÃ©dient', 'error'); return; }
    const qty = parseFloat(form.quantity);
