    setSubmitting(true);
    try {
      const res = await fetch(`${API_BASE}/waste`, {
        method: 'POST',
        headers: authHeaders(),
        body: JSON.stringify({
          ingredientId: ing.id,
          ingredientName: ing.name,
          quantity: qty,
          unit: ing.unit,
          costPerUnit: ing.pricePerUnit,
          reason: form.reason,
          notes: form.notes,
          date: todayStr,
        }),
      });
      if (!res.ok) {
        const body = await res.json().catch(() => ({})) as { error?: string };
        throw new Error(body.error || 'Erreur lors de la dÃ©claration');
      }
      setForm({ ingredientId: '', quantity: '', reason: 'expired', notes: '' });
      setShowAddModal(false);
      showToast(`Perte dÃ©clarÃ©e : ${qty} ${ing.unit} de ${ing.name} (${formatEuro(qty * ing.pricePerUnit)})`, 'success');
      await loadEntries();
    } catch (err: unknown) {
      showToast(err instanceof Error ? err.message : 'Erreur dÃ©claration', 'error');
    } finally {
      setSubmitting(false);
    }
  }

