// â”€â”€ Unit conversion divisor (price is always per bulk unit: kg/L) â”€â”€â”€â”€â”€â”€â”€â”€
function getUnitDivisor(unit: string): number {
  const u = (unit || '').toLowerCase().trim();
  if (u === 'g') return 1000;
  if (u === 'mg') return 1000000;
  if (u === 'cl') return 100;
  if (u === 'ml') return 1000;
  if (u === 'dl') return 10;
  return 1;
}

