                  ? 'bg-teal-100 dark:bg-teal-900/30 text-teal-700 dark:text-teal-300 border border-teal-300 dark:border-teal-700'
                  : 'bg-teal-600 text-white hover:bg-teal-700'
              }`}
            >
              {status === 'connected' ? (
                <><Wifi className="w-4 h-4" /> ConnectÃ©e</>
